	res := runExecuteBead(t, f, git, "gate-bead")

	assert.Equal(t, "merged", res.Outcome)
	require.Len(t, res.GateResults, 1, "required gate must be evaluated")
	assert.Equal(t, "pass", res.GateResults[0].Status)
}

